solution_code:
#include <iostream>

class Sensor {
public:
    static inline int s_created{ 0 };

    Sensor() { ++s_created; }

    static void printCreated() {
        std::cout << "Created: " << s_created << "\n";
    }
};

int main() {
    int n;
    std::cin >> n;
    for (int i{ 0 }; i < n; ++i) {
        Sensor s;
    }
    Sensor::printCreated();
    return 0;
}

