solution_code:
#include <iostream>

class Accumulator {
public:
    static inline int s_total{ 0 };

    static int addValue(int v) {
        s_total += v;
        return s_total;
    }
};

int main() {
    int n;
    std::cin >> n;
    for (int i{ 0 }; i < n; ++i) {
        int val;
        std::cin >> val;
        int total{ Accumulator::addValue(val) };
        std::cout << "Total: " << total << "\n";
    }
    return 0;
}
